input.content:
:root {
  --bg: #f6f1e7;
  --panel: #fffdf8;
  --ink: #2b2620;
  --muted: #8a7f6f;
  --line: #e7ddcb;
  --agent-bg: #fffdf8;
  --agent-line: #e7ddcb;
  --guest-bg: #2f5d50;     /* deep basil green */
  --guest-ink: #f6f1e7;
  --accent: #b5462f;       /* terracotta */
  --code-bg: #2b2620;
  --code-ink: #f3d9a0;
  --shadow: 0 10px 30px rgba(43, 38, 32, 0.10);
  --radius: 16px;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  height: 100%;
  background: var(--bg);
  color: var(--ink);
  font-family: -apple-system, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.app {
  max-width: 720px;
  margin: 0 auto;
  height: 100dvh;
  display: flex;
  flex-direction: column;
  background: var(--panel);
  box-shadow: var(--shadow);
}

/* Topbar */
.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 18px;
  border-bottom: 1px solid var(--line);
  background: linear-gradient(180deg, #fffdf8, #f9f3e7);
}
.brand { display: flex; align-items: center; gap: 12px; }
.brand-mark {
  font-size: 26px;
  width: 44px; height: 44px;
  display: grid; place-items: center;
  background: var(--bg);
  border: 1px solid var(--line);
  border-radius: 50%;
}
.brand h1 {
  font-family: Georgia, "Times New Roman", serif;
  font-size: 22px; margin: 0; letter-spacing: 0.2px;
}
.tagline { margin: 0; font-size: 12px; color: var(--muted); }
.reset {
  border: 1px solid var(--line);
  background: var(--panel);
  color: var(--muted);
  padding: 8px 12px;
  border-radius: 999px;
  font-size: 13px;
  cursor: pointer;
}
.reset:hover { color: var(--ink); border-color: var(--muted); }

/* Transcript */
.transcript {
  flex: 1;
  overflow-y: auto;
  padding: 20px 18px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  scroll-behavior: smooth;
}

.msg { display: flex; max-width: 82%; }
.msg.guest { align-self: flex-end; justify-content: flex-end; }
.msg.agent { align-self: flex-start; }

.bubble {
  padding: 11px 14px;
  border-radius: var(--radius);
  line-height: 1.45;
  font-size: 15px;
  white-space: pre-wrap;
  word-wrap: break-word;
}
.msg.agent .bubble {
  background: var(--agent-bg);
  border: 1px solid var(--agent-line);
  border-bottom-left-radius: 5px;
  color: var(--ink);
}
.msg.guest .bubble {
  background: var(--guest-bg);
  color: var(--guest-ink);
  border-bottom-right-radius: 5px;
}
.msg.error .bubble {
  background: #fdecea;
  border: 1px solid #f3c0b8;
  color: #8a2c1c;
}

/* Confirmation code badge */
.code {
  display: inline-block;
  font-family: "SFMono-Regular", Consolas, "Liberation Mono", monospace;
  background: var(--code-bg);
  color: var(--code-ink);
  padding: 1px 8px;
  border-radius: 6px;
  font-weight: 600;
  letter-spacing: 1px;
}

/* Typing indicator */
.typing .bubble { display: inline-flex; gap: 5px; align-items: center; }
.dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--muted);
  animation: blink 1.2s infinite ease-in-out;
}
.dot:nth-child(2) { animation-delay: 0.2s; }
.dot:nth-child(3) { animation-delay: 0.4s; }
@keyframes blink {
  0%, 80%, 100% { opacity: 0.25; transform: translateY(0); }
  40% { opacity: 1; transform: translateY(-2px); }
}

/* Composer */
.composer {
  border-top: 1px solid var(--line);
  padding: 12px 14px 14px;
  background: var(--panel);
}
#chat-form { display: flex; gap: 10px; }
#message-input {
  flex: 1;
  padding: 12px 14px;
  border: 1px solid var(--line);
  border-radius: 999px;
  font-size: 15px;
  outline: none;
  background: var(--bg);
  color: var(--ink);
}
#message-input:focus { border-color: var(--guest-bg); background: #fff; }
#send-btn {
  border: none;
  background: var(--accent);
  color: #fff;
  font-weight: 600;
  padding: 0 20px;
  border-radius: 999px;
  cursor: pointer;
  font-size: 15px;
}
#send-btn:hover { filter: brightness(1.05); }
#send-btn:disabled { opacity: 0.5; cursor: default; }
.hint { margin: 8px 4px 0; font-size: 11.5px; color: var(--muted); text-align: center; }

@media (max-width: 480px) {
  .app { box-shadow: none; }
  .msg { max-width: 90%; }
  .brand h1 { font-size: 20px; }
}

