export const meta = {
  name: 'bella-vista-review',
  description: 'Adversarial multi-dimension review of the Bella Vista reservation agent vs its BRD',
  phases: [{ title: 'Review', detail: 'one reviewer per dimension' }, { title: 'Verify', detail: 'adversarially refute each finding' }],
}

const ROOT = String((args && args.root) || 'C:/Users/user/.claude/bella_vista')
const BRD = String((args && args.brd) || 'C:/Users/user/Downloads/BRD-restaurant-reservation-agent.md')

const FINDINGS_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        properties: {
          id: { type: 'string' },
          severity: { type: 'string', enum: ['high', 'medium', 'low'] },
          title: { type: 'string' },
          file: { type: 'string' },
          line: { type: 'integer' },
          evidence: { type: 'string' },
          suggested_fix: { type: 'string' },
        },
        required: ['id', 'severity', 'title', 'file', 'line', 'evidence', 'suggested_fix'],
      },
    },
  },
  required: ['findings'],
}

const VERDICT_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    is_real: { type: 'boolean' },
    reasoning: { type: 'string' },
    severity: { type: 'string', enum: ['high', 'medium', 'low', 'none'] },
  },
  required: ['is_real', 'reasoning', 'severity'],
}

const preamble =
  `You are reviewing a restaurant reservation agent. The BRD is at ${BRD}. The code is under ${ROOT}. ` +
  `Read the relevant files yourself (Read/Grep). Report ONLY genuine issues — real bugs, requirement gaps, ` +
  `or security holes — not style nits or speculative concerns. For each, give the file path, an approximate ` +
  `line number, concrete evidence quoted from the code, a severity, and a concrete fix. Set a stable id like ` +
  `"<dim>-1". If the code is correct, return an empty findings array. Be precise and skeptical.`

const DIMENSIONS = [
  { key: 'requirements', prompt: preamble + `\n\nDIMENSION: Requirements coverage. Verify the implementation satisfies EVERY BRD requirement: business objectives BO-1..4; user-story acceptance criteria US-1..6; business rules BR-1..9; the §9 persisted schema (exact 9 fields, status values, created_at format); §8 seed data (table inventory 4x2/6x4/2x6, the BV-DEMO reservation); and §6.2 backend (POST /chat, a session mechanism, persistence that survives restart, each tool invocation logged to console). Read reservation_agent/{tools,config,store,models,agent}.py and app.py. Flag any requirement missing, partial, or wrong.` },
  { key: 'correctness', prompt: preamble + `\n\nDIMENSION: Correctness & state integrity. Can a double-booking EVER occur? Examine the table allocator for edge cases (parties of 7-8 combining; both six-tops taken; seat-sum vs table-level). Does modify_reservation release the old slot AND re-validate the new slot excluding itself? Does cancel release the slot? Is BR-8 (one active reservation per date per phone) enforced on BOTH create and modify? Does store.transaction() actually close the check-then-act (TOCTOU) race? Read reservation_agent/{allocator,tools,store,clock}.py.` },
  { key: 'tooldesign', prompt: preamble + `\n\nDIMENSION: Tool design & validation. Do the tools fail loudly on malformed/garbage input (bad date/time strings, non-integer party size, empty name, junk phone)? Could any tool or the dispatcher raise an UNHANDLED exception that 500s the server? Are confirmation codes unique and well-formed? Read reservation_agent/{tools,errors,agent,codes}.py.` },
  { key: 'conversation', prompt: preamble + `\n\nDIMENSION: Conversation quality (deterministic brain). Find user inputs that get mishandled: out-of-order info, mid-booking corrections, refusals (US-6) that fire wrongly or fail to fire, name/date/time/party extraction false-positives or misses, a flow that gets stuck in a loop or a dead end, or confirmations that execute without consent. Read reservation_agent/{nlu,agent,formatting}.py.` },
  { key: 'webux', prompt: preamble + `\n\nDIMENSION: Web UX & frontend/backend separation. In static/app.js check for XSS via innerHTML, the typing/loading indicator, error-state handling, autoscroll, Enter-to-send, and the confirmation-code badge. In app.py check the FE/BE boundary (is it clean — could the UI be swapped?), cookie flags, and request validation. Read static/{app.js,index.html,styles.css} and app.py.` },
  { key: 'security', prompt: preamble + `\n\nDIMENSION: Security. Assess XSS (innerHTML in app.js with agent-controlled text), prompt-injection resistance (can user text or tool output drive unsafe actions?), path traversal, unvalidated input reaching the store, the BV_DATA_FILE env, and the LLM adapter. Read static/app.js, app.py, reservation_agent/{llm,tools,store}.py.` },
]

log(`Reviewing ${DIMENSIONS.length} dimensions of ${ROOT}`)

const reviewed = await pipeline(
  DIMENSIONS,
  d => agent(d.prompt, { label: `review:${d.key}`, phase: 'Review', schema: FINDINGS_SCHEMA, effort: 'medium' }),
  (review, d) => {
    const findings = (review && review.findings) || []
    if (!findings.length) return []
    return parallel(findings.map(f => () =>
      agent(
        `Adversarially verify this code-review finding. Read the actual file "${f.file}" under ${ROOT} ` +
        `around line ${f.line} and the surrounding code before judging. Decide if it is a REAL, reproducible ` +
        `issue given the ACTUAL code — not a misunderstanding of how the code works. Default to is_real=false ` +
        `if the code already handles it, the concern is speculative, or you cannot confirm it from the code. ` +
        `\n\nDimension: ${d.key}\nTitle: ${f.title}\nClaimed evidence: ${f.evidence}\nSuggested fix: ${f.suggested_fix}`,
        { label: `verify:${f.id}`, phase: 'Verify', schema: VERDICT_SCHEMA, effort: 'high' },
      ).then(v => ({ ...f, dimension: d.key, verdict: v })).catch(() => null),
    ))
  },
)

const all = reviewed.flat().filter(Boolean)
const confirmed = all.filter(f => f.verdict && f.verdict.is_real)
log(`Findings raised: ${all.length}; confirmed real after adversarial verify: ${confirmed.length}`)

return {
  raised: all.length,
  confirmed_count: confirmed.length,
  confirmed: confirmed.map(f => ({
    dimension: f.dimension, severity: (f.verdict && f.verdict.severity) || f.severity,
    title: f.title, file: f.file, line: f.line,
    evidence: f.evidence, suggested_fix: f.suggested_fix,
    verifier_reasoning: f.verdict && f.verdict.reasoning,
  })),
}

